onSubmit:
{{
  storeValue("lokalizacjeData", [])
    .then(() =>
      Number(RadioRodzaj.selectedOptionValue) === 0
        ? getSzukajMiejscowosc.run()
        : Number(RadioRodzaj.selectedOptionValue) === 1
          ? getSzukajGmina.run()
          : Number(RadioRodzaj.selectedOptionValue) === 2
            ? getSzukajPowiat.run()
            : []
    )
    .then((data) => {
      storeValue("lokalizacjeData", data || []);
    })
}}

onTextChanged:
{{
  storeValue("lokalizacjeData", [])
    .then(() =>
      Number(RadioRodzaj.selectedOptionValue) === 0
        ? Promise.all([
            getSzukajMiejscowosc.run(),
            getCzyKSRRmiasto.run()
          ]).then(([data]) => data)
        : Number(RadioRodzaj.selectedOptionValue) === 1
          ? getSzukajGmina.run()
          : Number(RadioRodzaj.selectedOptionValue) === 2
            ? getSzukajPowiat.run()
            : []
    )
    .then((data) => {
      storeValue("lokalizacjeData", data || []);
    })
}}
